# Remove duplicates by sequence (keep first occurrence)
seen = set()
unique = []
for entry in ALL:
    seq = entry["peptide_info"]["decoy_sequence"]
    if seq not in seen:
        seen.add(seq)
        unique.append(entry)
    else:
        print(f"  Skipping duplicate: DC-{entry['decoy_id']} {seq}")

# Re-number
for i, entry in enumerate(unique, 1):
    entry["decoy_id"] = f"DC-{i:04d}"

out = os.path.join(os.path.dirname(__file__), "data", "seed_entries.json")
os.makedirs(os.path.dirname(out), exist_ok=True)
with open(out, "w") as f:
    json.dump(unique, f, indent=2, ensure_ascii=False)
print(f"Wrote {len(unique)} entries to {out}")
